/// Configuration for registering a custom LLM provider at runtime.
#[derive(Clone, Default)]
#[wasm_bindgen]
pub struct WasmCustomProviderConfig {
    name: String,
    base_url: String,
    auth_header: WasmAuthHeaderFormat,
    model_prefixes: Vec<String>,
}

#[wasm_bindgen]
impl WasmCustomProviderConfig {
    #[wasm_bindgen(constructor)]
    pub fn new(
        name: String,
        base_url: String,
        auth_header: WasmAuthHeaderFormat,
        model_prefixes: Vec<String>,
    ) -> WasmCustomProviderConfig {
        WasmCustomProviderConfig {
            name,
            base_url,
            auth_header,
            model_prefixes,
        }
    }

    #[wasm_bindgen(getter)]
    pub fn name(&self) -> String {
        self.name.clone()
    }

    #[wasm_bindgen(setter)]
    pub fn set_name(&mut self, value: String) {
        self.name = value;
    }

    #[wasm_bindgen(getter, js_name = "baseUrl")]
    pub fn base_url(&self) -> String {
        self.base_url.clone()
    }

    #[wasm_bindgen(setter, js_name = "baseUrl")]
    pub fn set_base_url(&mut self, value: String) {
        self.base_url = value;
    }

    #[wasm_bindgen(getter, js_name = "authHeader")]
    pub fn auth_header(&self) -> WasmAuthHeaderFormat {
        self.auth_header
    }

    #[wasm_bindgen(setter, js_name = "authHeader")]
    pub fn set_auth_header(&mut self, value: WasmAuthHeaderFormat) {
        self.auth_header = value;
    }

    #[wasm_bindgen(getter, js_name = "modelPrefixes")]
    pub fn model_prefixes(&self) -> Vec<String> {
        self.model_prefixes.clone()
    }

    #[wasm_bindgen(setter, js_name = "modelPrefixes")]
    pub fn set_model_prefixes(&mut self, value: Vec<String>) {
        self.model_prefixes = value;
    }
}

